import React from 'react';
import {
  Card,
  Stack,
  Box,
  Heading,
  Text,
  Divider
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{
    day?: string;
    icon?: string;
    high?: number;
    low?: number;
  }>;
}

/**
 * WeatherCard Component
 * 
 * A comprehensive weather overview component that displays current conditions
 * and a 5-day forecast strip. Designed to be theme-compatible using GGUI design tokens.
 */
const WeatherCard: React.FC<Props> = ({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}) => {
  const hasForecast = forecast && forecast.length > 0;

  return (
    <Card
      shadow="md"
      radius="xl"
      padding={24}
      role="region"
      aria-label={`${city} Weather Overview`}
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        width: '100%',
        maxWidth: '100%'
      }}
    >
      <Stack gap={24}>
        {/* Header Section: City and Condition */}
        <Stack gap={4}>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text
            variant="bodyLarge"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {condition}
          </Text>
        </Stack>

        {/* Main Temperature Display */}
        <Box>
          <Text
            size="4xl"
            weight="bold"
            align="left"
            color="var(--ggui-color-primary-600, #0284c7)"
            aria-live="polite"
          >
            {temperature}°{unit}
          </Text>
        </Box>

        {/* Atmospheric Metrics Row */}
        <Stack direction="horizontal" gap={16} justify="start">
          {/* Humidity Item */}
          <Stack gap={0}>
            <Text
              variant="caption"
              weight="semibold"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              style={{ textTransform: 'uppercase' }}
            >
              HUMIDITY
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed Item */}
          <Stack gap={0}>
            <Text
              variant="caption"
              weight="semibold"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              style={{ textTransform: 'uppercase' }}
            >
              WIND
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        {/* Forecast Strip Section */}
        {hasForecast && (
          <>
            <Divider
              margin={16}
              color="var(--ggui-color-outlineVariant, #e4e4e7)"
            />
            <Stack direction="horizontal" justify="between" align="center" wrap={false}>
              {forecast.map((item, index) => (
                <Stack
                  key={`${item.day ?? 'day'}-${index}`}
                  direction="vertical"
                  align="center"
                  gap={8}
                >
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {item.day ?? '---'}
                  </Text>

                  <Box aria-label={item.icon ? `Weather condition: ${item.icon}` : undefined}>
                    <Text size="xl">
                      {item.icon ?? '❓'}
                    </Text>
                  </Box>

                  <Stack direction="horizontal" gap={4}>
                    <Text
                      variant="caption"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {item.high ?? '--'}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {item.low ?? '--'}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </>
        )}
      </Stack>
    </Card>
  );
};

export default WeatherCard;
